  bool FileOps::replace (char const * filenameOld, char const * filenameNew)
                                                                              {
		#ifdef _WIN32
			return MoveFileExA(filenameOld, filenameNew, MOVEFILE_REPLACE_EXISTING | MOVEFILE_WRITE_THROUGH) != 0;
		#else
			return ::rename(filenameOld, filenameNew) == 0;
		#endif
		}
