namespace sttSav
{
  template <typename NODE, typename UNPACKED_KEY>
  NODE * DictionaryLookup <NODE, UNPACKED_KEY>::lookup (NODE * start, UNPACKED_KEY const & key)
                                                                  {
		NODE* current = start;
		while (current) {
			NODE* exact = NULL;
			NODE* remainder = NULL;
			
			if (!current->children.size())
				return current;
			for (NODE* child : current->children) {
				if (child->containsExact(key)) {
					exact = child;
					break;
					}
				else if (child->isRemainder())
					remainder = child;
				}
			if (exact)
				current = exact;
			else if (remainder)
				current = remainder;
			else
				return current;
			}
		return NULL;
		}
}
namespace sttSav
{
  template <typename NODE, typename UNPACKED_KEY>
  void DictionaryLookup <NODE, UNPACKED_KEY>::extractArchiveIdsWorker (uint32_t & workingCount, archiveId * archivesOut, uint32_t & numArchivesOut, uint32_t const maxArchivesOut) const
                                                                                                                                                    {
		for (uint32_t i = 0; i < mLookup.size(); ++i) {
			if (mLookup[i].ptr) {
				if (archivesOut && numArchivesOut < maxArchivesOut) {
					archivesOut[numArchivesOut] = mLookup[i].aid;
					numArchivesOut++;
					}
				workingCount++;
				}
			}
		}
}
namespace sttSav
{
  template <typename NODE, typename UNPACKED_KEY>
  bool DictionaryMergeHelper <NODE, UNPACKED_KEY>::getMergeCandidatesWorker (DictionaryLookup <NODE,UNPACKED_KEY> const & mLookup, archiveId const id, archiveId * archivesOut, uint32_t & numArchivesOut, uint32_t const maxArchivesOut)
                                                                                                                                                                                                      {
		numArchivesOut = 0;
		NODE* n = mLookup.getNodeByArchiveId(id);
		if (!n)
			return false;
		NODE* parent = n->parent;
		if (!parent)
			return false;

		// Parent must be a routing node.
		if (parent->aid.value != 0)
			return false;
			
		// Root and PLANET-R are never merged.
		if (!n->isAllowedToMerge())
			return false;
			
		for (const NODE* child : parent->children) {
			if (!child->aid.value)
				return false; // malformed routing node
			STTSAV_ASSERT(numArchivesOut < maxArchivesOut);
			archivesOut[numArchivesOut++] = child->aid;
			}
		return numArchivesOut != 0;
		}
}
namespace sttSav
{
  template <typename NODE, typename UNPACKED_KEY>
  bool DictionaryMergeHelper <NODE, UNPACKED_KEY>::mergeArchivesWorker (DictionaryLookup <NODE,UNPACKED_KEY> & mLookup, archiveId const * archives, uint32_t const numArchives)
                                                                                                                                             {
		if (!numArchives)
			return false;

		NODE* first = mLookup.getNodeByArchiveId(archives[0]);
		if (!first)
			return false;
		NODE* parent = first->parent;
		if (!parent)
			return false;

		// Parent must currently be routing.
		STTSAV_ASSERT(parent->aid.value == 0);

		// Verify every archive belongs to this parent.
		for (uint32_t i = 0; i < numArchives; ++i) {
			NODE* n = mLookup.getNodeByArchiveId(archives[i]);
			if (!n)
				return false;
			if (n->parent != parent)
				return false;
			}

		// Delete every child.
		while (!parent->children.empty()) {
			NODE* child = parent->children.back();
			parent->children.pop_back();
			mLookup.clearLookup(child->aid);
			STTSAV_DEL(child, sizeof(NODE));
			}
		// Parent becomes an archive again.
		parent->aid = mLookup.getNextId();
		mLookup.insertLookup(parent);
		return true;
		}
}
