  BinaryValue BinaryValue::operator [] (uint32_t index) const
                                                     {
		STTSAV_ASSERT(IsValid());
		STTSAV_ASSERT(IsArray());
		STTSAV_ASSERT(index < Size());

		uint64_t off = childOffset();

		for (uint32_t i = 0; i < index; ++i) {
			BinaryValue v;
			v.dec = dec;
			v.offset = off;
			off = v.nextOffset();
			}

		BinaryValue out;
		out.dec = dec;
		out.offset = off;
		return out;
		}
