  bool ArchiveFile::deleteRecord (recordId const id)
                                             {
		STTSAV_ASSERT(hasLoadedRecords);

		//if (id.value == 1136) // canary testing
		//	printf("DELETE RECORD 1136\n");
			
		// Remove any pending entry
		uint32_t p = findPendingRecord(id);
		while (p < pendingRecords.size()) {
			pendingRecords.erase(pendingRecords.begin() + p);
			p = findPendingRecord(id);
			}

		// Does it exist on disc?
		uint32_t idx = findRecord(id);
		if (idx >= records.size())
			return true; // not found, we don't need a tombstone

		recordInfo tombstone = records[idx];
		tombstone.length = 0;

		pendingRecords.push_back(tombstone);
		return true;
		}
