namespace sttSav
{
  bool ArchiveFile::loadRecordsWorker ()
                                 {
		// Returns TRUE if archive is ok or truncated and we can recover feilds
		// Returns FALSE if archive is corrupt and unusable
		if (!fileExists) {
			hasLoadedRecords = true;
			return true;
			}
		STTSAV_ASSERT(file.isOpen());
		fileLength = file.length();

		// Empty file?
		if (fileLength < sizeof(ArchiveFileHeader)) {
			hasLoadedRecords = true;
			lastDirectoryOffsetAddr = ArchiveFileHeader::getDirectoryOffsetAddr(0);
			return true;
			}

		// Read archive header.
		if (!file.seek(0))
			return false;

		if (!file.read(mHeader))
			return false;

		// Invalid archive.
		if (mHeader.magic != archiveConstants::ARCHIVE_MAGIC || mHeader.version != archiveConstants::ARCHIVE_VERSION)
			return false;

		// First directory has been truncated
		if (mHeader.directoryOffset > fileLength)
			return false;

		// No directories yet.
		if (mHeader.directoryOffset == 0) {
			hasLoadedRecords = true;
			lastDirectoryOffsetAddr = ArchiveFileHeader::getDirectoryOffsetAddr(0);
			return true;
			}

		uint64_t directoryOffset = mHeader.directoryOffset;

		while (directoryOffset) {
			// Truncated / corrupt tail.
			if (directoryOffset >= fileLength)
				break;
			if (!file.seek(directoryOffset))
				break;
			ArchiveDirectoryHeader dh;
			if (!file.read(dh))
				break;
			// Validate that the entire delta fits in the file.
			const uint64_t deltaEnd = directoryOffset + sizeof(ArchiveDirectoryHeader) + uint64_t(dh.numRecords) * sizeof(recordInfo);

			if (deltaEnd > fileLength)
				break;

			STTSAV_VECTOR<recordInfo> delta;
			delta.resize(dh.numRecords);

			if (!file.readArray(delta.data(), dh.numRecords))
				break;

			// Apply this delta.
			applyDeltas(delta, false);

			// Remember where the next directory pointer lives.
			lastDirectoryOffsetAddr = ArchiveDirectoryHeader::getDirectoryOffsetAddr(directoryOffset);

			// Self-loop protection.
			if (dh.nextDirectoryOffset == directoryOffset)
				break;

			directoryOffset = dh.nextDirectoryOffset;
			}
			
		// calcualte the waste
		uint64_t liveBlobBytes = 0;
		for (const recordInfo& r : records)
			liveBlobBytes += r.length;
		const uint64_t liveBytes = sizeof(ArchiveFileHeader) + uint64_t(records.size()) * sizeof(recordInfo) + liveBlobBytes;
		STTSAV_ASSERT(fileLength >= liveBytes);
		wastedBytes = fileLength - liveBytes;

		hasLoadedRecords = true;
		fileLength = file.length();
		return true;
		}
}
namespace sttSav
{
  void ArchiveFile::initNewFileWorker ()
                                 {
		STTSAV_ASSERT(file.isOpen());
		
		initHeader();
		lastDirectoryOffsetAddr = mHeader.getDirectoryOffsetAddr(0);
		hasLoadedRecords = true;
		
		if (!file.write(mHeader))
			STTSAV_ASSERT(false);

		fileLength = sizeof(ArchiveFileHeader);
		}
}
namespace sttSav
{
  bool ArchiveFile::prepareFileForReading ()
                                     {
		if (file.isOpen())
			return true;
		if (!fileExists) {
			hasLoadedRecords = true;
			return true;
			}
		if (!file.openRead(filename.c_str()))
			return false;
		if (!hasLoadedRecords)
			loadRecords();
		return true;
		}
}
namespace sttSav
{
  bool ArchiveFile::prepareFileForRecordDeletion ()
                                            {
		if (!fileExists) {
			hasLoadedRecords = true;
			return true;
			}
		return prepareFileForWriting();
		}
}
namespace sttSav
{
  bool ArchiveFile::prepareFileForWriting ()
                                     {
		// Already open for read/write?
		if (file.isOpen() && file.getMode() == FileHandle::OM_READ_WRITE)
			return true;

		// Upgrade a read-only handle.
		if (file.isOpen())
			file.close();

		if (!fileExists) {
			// First write to this archive.
			if (!file.openReadWrite(filename.c_str(), true))
				return false;

			initNewFileWorker();
			}
		else {
			// Existing archive.
			if (!file.openReadWrite(filename.c_str(), false))
				return false;
				
			if (!hasLoadedRecords) {
				bool isOk = loadRecordsWorker();
				
				if (!isOk) {
					// corrupted. create a new blank file
					if (!file.truncateAndReopen(filename.c_str()))
						return false;
					initNewFileWorker();
					}
				}
			}

		return true;
		}
}
namespace sttSav
{
  void ArchiveFile::applyDeltas (STTSAV_VECTOR <recordInfo> const & deltas, bool const updateWastedBytes)
                                                                                                {
		for (const recordInfo& r : deltas) {
			//if (r.record.value == 1136) // canary testing
			//	printf("APPLY DELTA 1136\n");
			uint32_t idx = findRecord(r.record);
			if (r.length == 0) {
				// Delete existing record.
				if (updateWastedBytes)
					wastedBytes += records[idx].length;
				if (idx < records.size())
					records.erase(records.begin() + idx);
					
				continue;
				}
			if (idx < records.size()) {
				// Replace existing record.
				if (updateWastedBytes)
					wastedBytes += records[idx].length;
				records[idx] = r;
				}
			else {
				// Insert new record, maintaining sorted order.
				auto it = std::lower_bound( records.begin(), records.end(), r.record, recordInfo::compareRecords());
				records.insert(it, r);
				}
			}
		}
}
namespace sttSav
{
  bool ArchiveFile::commit ()
                      {
		if (pendingRecords.empty())
			return true;

		// Phase 1 - get a valid write file handle
		if (!prepareFileForWriting()) {
			// error! we have no valid file handle
			return false;
			}
		STTSAV_ASSERT(hasLoadedRecords);

		// Phase 2 - write pending blob data to disc
		{
		file.seek(fileLength);
		for (recordInfo& r : pendingRecords) {
			if (r.length == 0)
				continue;
			const char* src = writeBuffer.data() + r.offset;
			if (!file.write(src, r.length))
				return false;
			r.offset = fileLength;
			fileLength += r.length;
			}
		}
		
		// Phase 3 - Write directory updates.
		const uint64_t newDirectoryOffset = fileLength;
		{
			ArchiveDirectoryHeader dh;
			dh.numRecords = pendingRecords.size();
			dh.reserved = 0;
			dh.nextDirectoryOffset = 0;

			if (!file.write(dh))
				return false;
			
			// Just memcpy the vector to file
			STTSAV_ASSERT(std::is_trivially_copyable<recordInfo>::value);
			if (!pendingRecords.empty())
				if (!file.writeArray( pendingRecords.data(), pendingRecords.size() ))
					return false;
				
			fileLength += sizeof(ArchiveDirectoryHeader) + (pendingRecords.size() * sizeof(recordInfo));
		}

		// Phase 4 - Link the new directory into the directory chain.
		{
			// Update the previous directory (or header for the first directory) to
			// point at this newly written directory.
			if (!file.seek(lastDirectoryOffsetAddr))
				return false;

			if (!file.write(newDirectoryOffset))
				return false;

			// Remember where this directory's "next directory" pointer lives.
			lastDirectoryOffsetAddr = ArchiveDirectoryHeader::getDirectoryOffsetAddr(newDirectoryOffset);
		}

		// Phase 5 - Apply pending changes to the in-memory directory.
		applyDeltas(pendingRecords, true);

		pendingRecords.clear();
		pendingRecords.shrink_to_fit();
		writeBuffer.clear();
		writeBuffer.shrink_to_fit();
		
		wastedBytes += sizeof(ArchiveDirectoryHeader);

		return true;
		}
}
namespace sttSav
{
  bool ArchiveFile::compact ()
                       {
		// Cleans the archive file, removing dead blobs and cleaning up the record directory
		
		// Nothing to compact.
		if (!fileExists)
			return true;
			
		// Ensure the archive is realised.
		if (!hasLoadedRecords) {
			if (!prepareFileForWriting())
				return false;
			}

		// Commit any pending writes first.
		if (!pendingRecords.empty()) {
			if (!commit())
				return false;
			}
			
		// Delete if no records
		if (!records.size()) {
			if (file.isOpen())
				file.close();
			FileOps::deleteFile(filename.c_str());
			fileExists = false;
			fileLength = 0;
			wastedBytes = 0;
			return true;
			}

		// Open source archive if necessary.
		if (!file.isOpen()) {
			if (!file.openRead(filename.c_str()))
				return false;
			}

		// Phase 1 - Create temporary archive.
		STTSAV_STRING tmpFilename = filename + ".tmp";

		FileHandle out;
		if (!out.openReadWrite(tmpFilename.c_str(), true))
			return false;
		
		// Guard to remove temp in case of failure
		struct tempFileGuard {
			FileHandle* tmpOut;
			const char* tmpName;
			
			~tempFileGuard() {
				if (tmpOut) {
					tmpOut->close();
					FileOps::deleteFile(tmpName);
					}
				}
			};
		tempFileGuard G;
		G.tmpOut = &out;
		G.tmpName = tmpFilename.c_str();

		// Start writing output
		ArchiveFileHeader newHeader;
		newHeader.magic = archiveConstants::ARCHIVE_MAGIC;
		newHeader.version = archiveConstants::ARCHIVE_VERSION;
		newHeader.reserved = 0;
		newHeader.directoryOffset = sizeof(ArchiveFileHeader);

		if (!out.write(newHeader))
			return false;

		uint64_t nextOffset = sizeof(ArchiveFileHeader);

		// Phase 2 - Copy all live blobs.
		STTSAV_STRING blobBuffer;

		for (recordInfo& r : records) {
			if (!FileHandle::copyRange(file, r.offset, r.length, out))
				return false;

			r.offset = nextOffset;
			nextOffset += r.length;
			}

		// Phase 3 - Write a single directory.
		const uint64_t directoryOffset = nextOffset;

		ArchiveDirectoryHeader dh;
		dh.numRecords = (uint32_t)records.size();
		dh.reserved = 0;
		dh.nextDirectoryOffset = 0;

		if (!out.write(dh))
			return false;

		if (!out.writeArray(records.data(), (uint32_t)records.size()))
			return false;
			
		nextOffset += sizeof(ArchiveDirectoryHeader) + (uint64_t(records.size()) * sizeof(recordInfo));

		// Phase 4 - Patch the header.
		newHeader.directoryOffset = directoryOffset;

		if (!out.seek(0))
			return false;

		if (!out.write(newHeader))
			return false;

		if (!out.flush())
			return false;

		out.close();
		G.tmpOut = NULL; // disarm the guard

		// Phase 5 - Replace the old archive.
		file.close();

		if (!FileOps::replace(tmpFilename.c_str(), filename.c_str()))
			return false;

		// Re-open lazily later.
		fileLength = nextOffset;
		wastedBytes = 0;
		lastDirectoryOffsetAddr = ArchiveDirectoryHeader::getDirectoryOffsetAddr(directoryOffset);
		return true;
		}
}
